mapper.select:
SELECT biz_id AS bizId, 1 AS behaviorType, UNIX_TIMESTAMP(order_time) * 1000 AS timestamp
FROM order_info
WHERE user_id = #{userId}
ORDER BY order_time DESC
LIMIT #{limit}

SELECT order_id, user_id, user_coupon_id AS couponId, order_time, amount, amount_paid, biz_id
FROM order_info
WHERE biz_id = #{bizId}
ORDER BY order_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM order_info
WHERE biz_id = #{bizId}
